# chatcli Remote Agent — 一键部署（不依赖 GitHub）
 = "Stop"
Write-Host "=== chatcli Remote Agent ===" -ForegroundColor Cyan

if (-not (Get-Command python -ErrorAction SilentlyContinue)) {
    Write-Host "请先装 Python 3.10+: https://python.org" -ForegroundColor Red; exit 1
}
Write-Host "Python: " -ForegroundColor Green

Write-Host "安装依赖..." -ForegroundColor Yellow
pip install fastapi uvicorn python-multipart --quiet
Write-Host "完成" -ForegroundColor Green

Write-Host "部署 Agent..." -ForegroundColor Yellow
 = @"

"@
 = [Text.Encoding]::UTF8.GetString([Convert]::FromBase64String( -replace '\s',''))
Set-Content -Path C:\chatcli_agent.py -Value  -Encoding UTF8

# 生成随机 Token
 = (48..57) + (65..90) + (97..122)
 = -join ( | Get-Random -Count 48 | ForEach { [char]F:/chatcli })
[Environment]::SetEnvironmentVariable("CHATCLI_GUEST_AGENT_TOKEN", , "Machine")
:CHATCLI_GUEST_AGENT_TOKEN = 

mkdir C:\analysis\cases, C:\analysis\outbox -Force | Out-Null
New-NetFirewallRule -DisplayName "chatcli Agent" -Direction Inbound -Protocol TCP -LocalPort 8443 -Action Allow -ErrorAction SilentlyContinue | Out-Null

Write-Host "" -ForegroundColor Green
Write-Host "=== 部署完成 ===" -ForegroundColor Cyan
Write-Host "Token: " -ForegroundColor Yellow
Write-Host ""  
Write-Host "chatcli 侧配置:" -ForegroundColor White
Write-Host "  remote:" -ForegroundColor Gray
Write-Host "    enabled: true" -ForegroundColor Gray
Write-Host "    base_url: http://<IP>:8443" -ForegroundColor Gray
Write-Host "    guest_agent_token: " -ForegroundColor Gray
Write-Host ""
python C:\chatcli_agent.py --host 0.0.0.0 --port 8443
